from flask import Flask, request, jsonify
import memcache

app = Flask(__name__)
mc = memcache.Client(['localhost:11211'], debug=0)

# Example database query function
def fetch_data_from_db(query):
    # Simulate a database operation with a delay
    import time
    time.sleep(1)
    return {"data": f"Result of {query}"}

@app.route('/api/data', methods=['GET'])
def get_data():
    query = request.args.get('query', 'default_query')
    
    # Try to fetch from cache first
    cached_result = mc.get(query)
    if cached_result:
        return jsonify(cached_result)
    
    # If not in cache, fetch data from DB and store in cache
    result = fetch_data_from_db(query)
    mc.set(query, result, time=300)  # Cache for 5 minutes (TTL: 300 seconds)
    
    return jsonify(result)

if __name__ == '__main__':
    app.run(debug=True, port=5000)